    "id": "Sección1-2258",
    "section": "Sección 1",
    "question": "¿Qué características debe reunir el alojamiento en el que un conductor tome el descanso semanal normal?",
    "options": {
      "D": "Todas las respuestas son correctas.",
      "B": "Que tenga instalaciones sanitarias adecuadas.",
      "A": "Que tenga instalaciones para dormir.",
      "C": "Que esté adaptado para ambos sexos."
    },
    "answer": "D",
    "norma": "Reglamento Comunitario (CE) 561/2006, art. 8.8",
    "referencia": "Sin referencias doctrinales"
