    "options": {
      "D": "A los tranvías y en ningún caso a los autobuses.",
      "B": "Exclusivamente a los tranvías y a los autobuses de líneas regulares.",
      "A": "A los tranvías solamente.",
      "C": "A los autobuses solamente."
    },
    "answer": "B",
    "norma": "RD 1428/2003, Anexo I, 4.4",
    "referencia": "Sin referencias doctrinales"
