    "options": {
      "D": "No hay establecido ningún número mínimo.",
      "B": "Dos.",
      "A": "Una.",
      "C": "Tres."
    },
    "answer": "A",
    "norma": "Reglamento CEPE 107, Anexo 3, 7.6.1.1",
